137	describe("Auth - Ownership", () => {
138	  let aliceToken: string;
139	  let bobToken: string;
140	  let alicePostId: number;
141	
142	  beforeAll(async () => {
143	    // Register two users
144	    const aliceRes = await request(app).post("/auth/register").send({
145	      username: "alice_owner",
146	      email: "alice_owner@example.com",
147	      password: "alicepass",
148	    });
149	    aliceToken = aliceRes.body.token;
150	
151	    const bobRes = await request(app).post("/auth/register").send({
152	      username: "bob_owner",
153	      email: "bob_owner@example.com",
154	      password: "bobpass",
155	    });
156	    bobToken = bobRes.body.token;
157	
158	    // Alice creates a post
159	    const postRes = await request(app)
160	      .post("/posts")
161	      .set("Authorization", `Bearer ${aliceToken}`)
162	      .send({
163	        title: "Alice's Post",
164	        content: "Only Alice can modify this",
165	      });
166	    alicePostId = postRes.body.id;
167	  });
168	
169	  it("owner can update their own post", async () => {
170	    const res = await request(app)
171	      .put(`/posts/${alicePostId}`)
172	      .set("Authorization", `Bearer ${aliceToken}`)
173	      .send({ title: "Alice's Updated Post" });
174	    expect(res.status).toBe(200);
175	    expect(res.body.title).toBe("Alice's Updated Post");
176	  });
177	
178	  it("non-owner cannot update someone else's post (403)", async () => {
179	    const res = await request(app)
180	      .put(`/posts/${alicePostId}`)
181	      .set("Authorization", `Bearer ${bobToken}`)
182	      .send({ title: "Bob tries to edit" });
183	    expect(res.status).toBe(403);
184	  });
185	
186	  it("non-owner cannot delete someone else's post (403)", async () => {
187	    const res = await request(app)
188	      .delete(`/posts/${alicePostId}`)
189	      .set("Authorization", `Bearer ${bobToken}`);
190	    expect(res.status).toBe(403);
191	  });
192	
193	  it("owner can delete their own post", async () => {
194	    const res = await request(app)
195	      .delete(`/posts/${alicePostId}`)
196	      .set("Authorization", `Bearer ${aliceToken}`);
197	    expect(res.status).toBe(200);
198	  });
199	});
